const checkpoints = [];
const copyEvents = JSON.parse(localStorage.getItem('copy_events') || '[]');
const apiCodeSamples = JSON.parse(localStorage.getItem('api_code_samples') || '[]');
const endpointVersions = JSON.parse(localStorage.getItem('api_endpoint_versions') || '[]');
// Identify POST /projects endpoint version dynamically
const postProjectsVersion = endpointVersions.find(function(v) {
  return v && v.path === '/projects' && String(v.httpMethod).toLowerCase() === 'post';
});
let nodeSample = null;
if (postProjectsVersion) {
  nodeSample = apiCodeSamples.find(function(s) {
    return s && s.endpointVersionId === postProjectsVersion.id && s.language === 'node_js' && s.sampleType === 'request' && !!s.isEditable;
  });
}
let matchingCopies = [];
if (nodeSample) {
  matchingCopies = copyEvents.filter(function(ev) {
    return ev && ev.sourceId === nodeSample.id;
  });
}
const updatedCopies = matchingCopies.filter(function(ev) {
  const content = ev && typeof ev.copiedContent === 'string' ? ev.copiedContent : '';
  const hasNew = content.indexOf('Sample Project A') !== -1;
  const hasOld = content.indexOf('My First Project') !== -1;
  return hasNew && !hasOld;
});
// CP1 (0.4): User copied the editable Node.js POST /projects sample at least once
checkpoints.push({ passed: matchingCopies.length > 0, weight: 0.4 });
// CP2 (0.6): Copied content shows the name field updated to use 'Sample Project A' instead of 'My First Project'
checkpoints.push({ passed: updatedCopies.length > 0, weight: 0.6 });
return checkpoints.reduce(function(sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

const checkpoints = [];
const t2 = JSON.parse(localStorage.getItem('task2_lastTryItRequest') || 'null');
const endpointVersions = JSON.parse(localStorage.getItem('api_endpoint_versions') || '[]');
const apiParams = JSON.parse(localStorage.getItem('api_parameters') || '[]');
// Find GET /users v1 endpoint version dynamically
const usersVersion = endpointVersions.find(function(v) {
  return v && v.path === '/users' && String(v.httpMethod).toLowerCase() === 'get';
});
function getQueryValue(name) {
  if (!t2 || !Array.isArray(t2.queryParams)) return null;
  const found = t2.queryParams.find(function(q) { return q && q.name === name; });
  if (!found || typeof found.value === 'undefined' || found.value === null) return null;
  return String(found.value);
}
function findParamDef(name) {
  if (!usersVersion) return null;
  return apiParams.find(function(p) {
    return p && p.endpointVersionId === usersVersion.id && p.name === name;
  });
}
// CP1 (0.4): Request was sent via Try-It for GET /users v1 (correct endpoint and method)
let cp1Passed = false;
if (t2 && usersVersion) {
  const method = (t2.method || '').toLowerCase();
  cp1Passed = t2.endpointVersionId === usersVersion.id && method === 'get' && t2.path === '/users';
}
checkpoints.push({ passed: cp1Passed, weight: 0.4 });
// CP2 (0.3): created_after is set to the example date from docs (e.g., '2023-01-01')
let cp2Passed = false;
if (t2 && usersVersion) {
  const def = findParamDef('created_after');
  const value = getQueryValue('created_after');
  if (def && typeof def.exampleValue !== 'undefined' && def.exampleValue !== null) {
    cp2Passed = value === String(def.exampleValue);
  }
}
checkpoints.push({ passed: cp2Passed, weight: 0.3 });
// CP3 (0.3): per_page is set to the non-default example value from docs (e.g., 25, not the default 20)
let cp3Passed = false;
if (t2 && usersVersion) {
  const def = findParamDef('per_page');
  const value = getQueryValue('per_page');
  if (def) {
    const exampleVal = typeof def.exampleValue !== 'undefined' && def.exampleValue !== null ? String(def.exampleValue) : null;
    const defaultVal = typeof def.defaultValue !== 'undefined' && def.defaultValue !== null ? String(def.defaultValue) : null;
    if (exampleVal && value === exampleVal && (!defaultVal || value !== defaultVal)) {
      cp3Passed = true;
    }
  }
}
checkpoints.push({ passed: cp3Passed, weight: 0.3 });
return checkpoints.reduce(function(sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

