const checkpoints = [];
const t4 = JSON.parse(localStorage.getItem('task4_viewedPaymentsRateLimitRule') || 'null');
const rules = JSON.parse(localStorage.getItem('rate_limit_rules') || '[]');
const endpoints = JSON.parse(localStorage.getItem('api_endpoints') || '[]');
// Identify the POST /payments endpoint dynamically
const paymentsEndpoint = endpoints.find(function(e) {
  return e && e.pathTemplate === '/payments' && String(e.primaryHttpMethod).toLowerCase() === 'post';
});
// Identify the matching endpoint-scoped per-minute rule for POST /payments
const targetRule = rules.find(function(r) {
  if (!r || r.scope !== 'endpoint') return false;
  const method = String(r.httpMethod || '').toLowerCase();
  const path = r.path || '';
  const timeWindow = r.timeWindow || '';
  if (method !== 'post' || path !== '/payments' || timeWindow !== 'per_minute') return false;
  if (paymentsEndpoint && r.endpointId && r.endpointId !== paymentsEndpoint.id) return false;
  return true;
});
// CP1 (0.7): Instrumentation shows viewing the POST /payments rule with per-minute limit 120
let cp1Passed = false;
if (t4 && targetRule) {
  const method = String(t4.primaryHttpMethod || '').toLowerCase();
  const pathTemplate = t4.pathTemplate || '';
  const perMin = (typeof t4.perMinuteLimit !== 'undefined' && t4.perMinuteLimit !== null) ? Number(t4.perMinuteLimit) : NaN;
  cp1Passed = method === 'post' && pathTemplate === '/payments' && perMin === 120;
}
checkpoints.push({ passed: cp1Passed, weight: 0.7 });
// CP2 (0.3): The viewed ruleId corresponds to the actual documented POST /payments per-minute rule
let cp2Passed = false;
if (t4 && targetRule) {
  cp2Passed = t4.ruleId === targetRule.id;
}
checkpoints.push({ passed: cp2Passed, weight: 0.3 });
return checkpoints.reduce(function(sum, cp) { return sum + (cp.passed ? cp.weight : 0); }, 0);

